from pathlib import Path

import numpy as np
import pandas as pd

WORKDIR = Path('/workspace/work')
INPUT_DIR = Path('/workspace/input')
OUTPUT_PATH = Path('/workspace/output/_slots/ps-1-normalize-and-validate-source-data/normalized_sources.json')
TMP_PATH = OUTPUT_PATH.with_suffix('.json.tmp')

csv_specs = [
    ('attachments/time_entries.csv', INPUT_DIR / 'attachments/time_entries.csv',
     ['work_date'], ['hours_logged', 'billed_rate', 'billed_amount']),
    ('attachments/contracts.csv', INPUT_DIR / 'attachments/contracts.csv',
     ['effective_date', 'expiration_date'], ['monthly_hours_cap']),
    ('attachments/rates.csv', INPUT_DIR / 'attachments/rates.csv',
     ['effective_date', 'expiration_date'], ['hourly_rate']),
    ('attachments/invoices.csv', INPUT_DIR / 'attachments/invoices.csv',
     ['period_start', 'period_end'], ['invoice_total']),
]

extra_inputs = [
    ('output/schema_profile_simone.json', INPUT_DIR / 'output/schema_profile_simone.json'),
    ('support/ps-0-profile-all-source-inputs/input_manifest.json', INPUT_DIR / 'support/ps-0-profile-all-source-inputs/input_manifest.json'),
    ('support/input_manifest.json', INPUT_DIR / 'support/input_manifest.json'),
]

print('Loading required inputs...', flush=True)
# Read non-CSV inputs required by the step contract.
for logical, path in extra_inputs:
    with path.open('r', encoding='utf-8') as f:
        data = json.load(f)
    if logical.endswith('schema_profile_simone.json'):
        if not isinstance(data, list):
            raise TypeError(f'Expected array at {logical}, found {type(data).__name__}')
        print(f'  {logical}: {len(data)} rows', flush=True)
    else:
        if not isinstance(data, dict):
            raise TypeError(f'Expected object at {logical}, found {type(data).__name__}')
        print(f'  {logical}: keys={list(data.keys())[:5]}', flush=True)

flags = []

def add_flag(source_file, row_index, column, issue_type, raw_value):
    flags.append({
        'source_file': source_file,
        'row_index': int(row_index),
        'column': column,
        'issue_type': issue_type,
        'raw_value': raw_value,
    })


def normalize_table(source_file, path, date_cols, numeric_cols):
    print(f'Loading {source_file}...', flush=True)
    df = pd.read_csv(path, dtype=str, keep_default_na=False, na_filter=False)
    print(f'  shape={df.shape}', flush=True)
    expected_rows = {'attachments/time_entries.csv': 753, 'attachments/contracts.csv': 7, 'attachments/rates.csv': 7, 'attachments/invoices.csv': 6}[source_file]
    if len(df) != expected_rows:
        raise ValueError(f'{source_file}: expected {expected_rows} rows, found {len(df)}')

    original_cols = list(df.columns)
    out = df.copy()

    for col in original_cols:
        trimmed = out[col].fillna('').astype(str).str.strip()
        missing_mask = trimmed.eq('')

        if col in date_cols:
            raw_col = f'raw_{col}'
            out[raw_col] = out[col]
            parsed = pd.to_datetime(trimmed.mask(missing_mask), errors='coerce')
            invalid_mask = (~missing_mask) & parsed.isna()
            for idx in out.index[missing_mask]:
                add_flag(source_file, idx, col, 'null_value', out.at[idx, col])
            for idx in out.index[invalid_mask]:
                add_flag(source_file, idx, col, 'type_error', out.at[idx, col])
            formatted = parsed.dt.strftime('%Y-%m-%d')
            formatted = formatted.where(parsed.notna(), None)
            out[col] = formatted
        elif col in numeric_cols:
            raw_col = f'raw_{col}'
            out[raw_col] = out[col]
            parsed = pd.to_numeric(trimmed.mask(missing_mask), errors='coerce')
            invalid_mask = (~missing_mask) & parsed.isna()
            for idx in out.index[missing_mask]:
                add_flag(source_file, idx, col, 'null_value', out.at[idx, col])
            for idx in out.index[invalid_mask]:
                add_flag(source_file, idx, col, 'type_error', out.at[idx, col])
            normalized = parsed.where(parsed.notna(), None)
            out[col] = normalized
        else:
            for idx in out.index[missing_mask]:
                add_flag(source_file, idx, col, 'null_value', out.at[idx, col])

    ordered_cols = []
    for col in original_cols:
        ordered_cols.append(col)
        if col in date_cols or col in numeric_cols:
            ordered_cols.append(f'raw_{col}')
    out = out[ordered_cols]
    records = out.to_dict(orient='records')
    return records

source_data = {}
source_data['time_entries'] = normalize_table('attachments/time_entries.csv', INPUT_DIR / 'attachments/time_entries.csv', ['work_date'], ['hours_logged', 'billed_rate', 'billed_amount'])
