source_data['rates'] = normalize_table('attachments/rates.csv', INPUT_DIR / 'attachments/rates.csv', ['effective_date', 'expiration_date'], ['hourly_rate'])
source_data['invoices'] = normalize_table('attachments/invoices.csv', INPUT_DIR / 'attachments/invoices.csv', ['period_start', 'period_end'], ['invoice_total'])

flags.sort(key=lambda r: (r['source_file'], r['row_index'], r['column'], r['issue_type']))

