}

# Recursive JSON cleaning to guarantee serializability and native Python scalar types.
def clean(obj):
    if isinstance(obj, dict):
        return {k: clean(v) for k, v in obj.items()}
    if isinstance(obj, list):
        return [clean(v) for v in obj]
    if obj is None:
        return None
    if isinstance(obj, (str, bool)):
        return obj
    if isinstance(obj, (int,)):
        return obj
    if isinstance(obj, (float,)):
        if math.isnan(obj) or math.isinf(obj):
            return None
        return obj
    if isinstance(obj, np.integer):
        return int(obj)
    if isinstance(obj, np.floating):
        val = float(obj)
        return None if math.isnan(val) or math.isinf(val) else val
    if obj is pd.NA:
        return None
    if isinstance(obj, pd.Timestamp):
        return obj.strftime('%Y-%m-%d')
    if pd.isna(obj):
        return None
    return obj

clean_payload = clean(payload)

print('Writing normalized_sources.json...', flush=True)
OUTPUT_PATH.parent.mkdir(parents=True, exist_ok=True)
with TMP_PATH.open('w', encoding='utf-8') as f:
    json.dump(clean_payload, f, ensure_ascii=False, indent=2, allow_nan=False)
os.replace(TMP_PATH, OUTPUT_PATH)

