if 'validation_flags' not in written or not isinstance(written['validation_flags'], list):
    raise AssertionError('validation_flags missing or not a list')

iso_re = re.compile(r'^\d{4}-\d{2}-\d{2}$')
checks = {
    'time_entries': {'date_fields': ['work_date'], 'numeric_fields': ['hours_logged', 'billed_rate', 'billed_amount']},
    'contracts': {'date_fields': ['effective_date', 'expiration_date'], 'numeric_fields': ['monthly_hours_cap']},
    'rates': {'date_fields': ['effective_date', 'expiration_date'], 'numeric_fields': ['hourly_rate']},
    'invoices': {'date_fields': ['period_start', 'period_end'], 'numeric_fields': ['invoice_total']},
}
for table, spec in checks.items():
    for row in written[table]:
        for col in spec['date_fields']:
            v = row[col]
            if v is not None and not (isinstance(v, str) and iso_re.match(v)):
                raise AssertionError(f'{table}.{col} invalid date value: {v!r}')
        for col in spec['numeric_fields']:
            v = row[col]
            if v is not None and not (isinstance(v, (int, float)) and not isinstance(v, bool)):
                raise AssertionError(f'{table}.{col} invalid numeric value: {v!r}')

size_bytes = OUTPUT_PATH.stat().st_size
if size_bytes <= 0:
    raise AssertionError('normalized_sources.json is empty')

summary = {
    'output_path': str(OUTPUT_PATH),
    'size_bytes': size_bytes,
    'lengths': {k: len(written[k]) for k in expected_lengths},
    'validation_flags': len(written['validation_flags']),
}
print(json.dumps(summary, indent=2), flush=True)
