        raise FileNotFoundError(f'missing input: {p}')
    print(f'  {p} size={p.stat().st_size}', flush=True)

policy_text = finance_policy_path.read_text(encoding='utf-8')
print(f'Loaded finance policy chars={len(policy_text)}', flush=True)

