    raise ValueError(f'Expected discrepancies array, got {type(discrepancies).__name__}')
print(f'Discrepancies rows={len(discrepancies)}', flush=True)

normalized = json.loads(normalized_path.read_text(encoding='utf-8'))
if not isinstance(normalized, dict):
    raise ValueError(f'Expected normalized_sources object, got {type(normalized).__name__}')
print(f'Normalized top-level keys={list(normalized.keys())}', flush=True)

invoices = normalized.get('invoices') or []
if not isinstance(invoices, list):
    raise ValueError(f'Expected invoices array, got {type(invoices).__name__}')
invoice_status_by_id = {}
for inv in invoices:
    if isinstance(inv, dict):
        inv_id = inv.get('invoice_id')
        if inv_id is not None:
            invoice_status_by_id[str(inv_id)] = inv.get('invoice_status')
print(f'Invoice lookup entries={len(invoice_status_by_id)}', flush=True)

# Aggregate candidate groups by (invoice_id, reason_code)
# Each value holds correction_amount and evidence refs.
groups = {}
possible_types = {'RATE_OVERCHARGE', 'RATE_UNDERCHARGE', 'AMOUNT_MISMATCH'}

for idx, row in enumerate(discrepancies):
    if not isinstance(row, dict):
        raise ValueError(f'Discrepancy row {idx} is {type(row).__name__}, expected object')
    invoice_id = row.get('invoice_id')
    time_entry_id = row.get('time_entry_id')
    discrepancy_types = row.get('discrepancy_types') or []
    if not isinstance(discrepancy_types, list):
        raise ValueError(f'Row {idx} discrepancy_types is {type(discrepancy_types).__name__}, expected array')

    overcharge_amount = row.get('overcharge_amount')
    amount_delta = row.get('amount_delta')
    for dtype in discrepancy_types:
        if dtype not in possible_types:
            continue
        if dtype == 'AMOUNT_MISMATCH':
            delta = amount_delta
        else:
            delta = overcharge_amount
        if delta is None:
            # preserve provenance; treat missing delta as zero but still include evidence? better to raise because input should be complete
            raise ValueError(f'Row {idx} missing delta for {dtype} (time_entry_id={time_entry_id})')
        key = (str(invoice_id), dtype)
        grp = groups.setdefault(key, {'invoice_id': str(invoice_id), 'reason_code': dtype, 'correction_amount': 0.0, 'evidence_refs': []})
        grp['correction_amount'] += abs(float(delta))
        grp['evidence_refs'].append(time_entry_id)

print(f'Candidate groups before policy={len(groups)}', flush=True)

# Build output rows applying business rules
output_rows = []
summary = {'eligible': 0, 'rejected': 0}
for (invoice_id, reason_code), grp in groups.items():
    correction_amount = float(grp['correction_amount'])
    invoice_status = invoice_status_by_id.get(str(invoice_id))
    evidence_refs = [str(x) for x in grp['evidence_refs'] if x is not None]
    if not evidence_refs:
        raise ValueError(f'Empty evidence_refs for invoice_id={invoice_id}, reason_code={reason_code}')

    status = 'eligible'
    approval_required = False
    rejection_reason = None

    if invoice_status == 'paid_locked':
        status = 'rejected'
        rejection_reason = 'invoice_locked'
    elif correction_amount > 100:
        status = 'rejected'
        rejection_reason = 'exceeds_max_correction'
    else:
        approval_required = correction_amount >= 25

    row = {
        'invoice_id': invoice_id,
        'correction_amount': round(correction_amount, 10),
        'reason_code': reason_code,
        'evidence_refs': evidence_refs,
        'status': status,
        'approval_required': bool(approval_required) if status == 'eligible' else False,
        'rejection_reason': rejection_reason,
        'invoice_status': invoice_status,
    }
    output_rows.append(row)
    summary[status] += 1

# Sort by invoice_id then reason_code
output_rows.sort(key=lambda r: (str(r['invoice_id']), str(r['reason_code'])))

# Validate all required fields and business rules
required_fields = ['invoice_id', 'correction_amount', 'reason_code', 'evidence_refs', 'status', 'approval_required', 'rejection_reason', 'invoice_status']
for i, row in enumerate(output_rows):
    missing = [f for f in required_fields if f not in row]
    if missing:
        raise ValueError(f'Output row {i} missing fields: {missing}')
    if not isinstance(row['evidence_refs'], list) or len(row['evidence_refs']) == 0:
        raise ValueError(f'Output row {i} has invalid evidence_refs: {row["evidence_refs"]!r}')
    if not isinstance(row['correction_amount'], (int, float)) or row['correction_amount'] < 0:
        raise ValueError(f'Output row {i} invalid correction_amount: {row["correction_amount"]!r}')
    if row['status'] == 'rejected' and row['rejection_reason'] is None:
        raise ValueError(f'Output row {i} rejected but rejection_reason is null')
    if row['status'] == 'eligible' and row['rejection_reason'] is not None:
        raise ValueError(f'Output row {i} eligible but rejection_reason not null')
    if row['correction_amount'] > 100 and row['status'] == 'eligible':
        raise ValueError(f'Output row {i} exceeds max but eligible')
    if row['invoice_status'] == 'paid_locked' and row['status'] == 'eligible':
        raise ValueError(f'Output row {i} locked invoice but eligible')
    if row['status'] == 'eligible' and not isinstance(row['approval_required'], bool):
        raise ValueError(f'Output row {i} approval_required not boolean')

out_path.parent.mkdir(parents=True, exist_ok=True)
out_path.write_text(json.dumps(output_rows, indent=2, ensure_ascii=False) + '\n', encoding='utf-8')

# Inline verification
exists = out_path.exists()
size = out_path.stat().st_size if exists else 0
print(json.dumps({
