from pathlib import Path

candidates_path = Path('/workspace/input/output/correction_candidates_simone.json')
normalized_path = Path('/workspace/input/output/_slots/ps-1-normalize-and-validate-source-data/normalized_sources.json')
out_path = Path('/workspace/output/correction_submission_result_simone.json')
out_path.parent.mkdir(parents=True, exist_ok=True)

print(f'Loading {candidates_path}...', flush=True)
with candidates_path.open('r', encoding='utf-8') as f:
    candidates = json.load(f)
print(f'Loading {normalized_path}...', flush=True)
with normalized_path.open('r', encoding='utf-8') as f:
    normalized = json.load(f)

if not isinstance(candidates, list):
    raise TypeError(f'Expected candidate array, got {type(candidates).__name__}')
if not isinstance(normalized, dict):
    raise TypeError(f'Expected normalized_sources object, got {type(normalized).__name__}')

invoices = normalized.get('invoices') or []
if not isinstance(invoices, list):
    raise TypeError(f'Expected normalized[\'invoices\'] list, got {type(invoices).__name__}')
invoice_lookup = {}
for inv in invoices:
    if isinstance(inv, dict) and inv.get('invoice_id') is not None:
        invoice_lookup[str(inv['invoice_id'])] = inv

sequence = 1
accepted = []
rejected = []
approval_required = []

for idx, cand in enumerate(candidates, start=1):
    if not isinstance(cand, dict):
        raise TypeError(f'Candidate #{idx} is not an object: {type(cand).__name__}')
    invoice_id = cand.get('invoice_id')
    correction_amount = cand.get('correction_amount')
    reason_code = cand.get('reason_code')
    evidence_refs = cand.get('evidence_refs') or []
    status = cand.get('status')
    invoice_status = invoice_lookup.get(str(invoice_id), {}).get('invoice_status', cand.get('invoice_status'))
    base = {
        'invoice_id': invoice_id,
        'correction_amount': correction_amount,
        'reason_code': reason_code,
        'evidence_refs': evidence_refs,
    }

    if status == 'rejected':
        rejected.append({**base, 'rejection_reason': cand.get('rejection_reason')})
        continue
    if status != 'eligible':
        raise ValueError(f"Unexpected candidate status for invoice_id={invoice_id!r}: {status!r}")

    if correction_amount is None:
        raise ValueError(f'missing correction_amount for invoice_id={invoice_id!r}')
    if invoice_status == 'paid_locked':
        rejected.append({**base, 'rejection_reason': 'invoice_locked'})
        continue
    if correction_amount > 100:
        rejected.append({**base, 'rejection_reason': 'exceeds_max_correction'})
        continue

    corr_id = f'CORR-{sequence:04d}'
    sequence += 1
    if correction_amount > 25:
        approval_required.append({**base, 'correction_id': corr_id, 'approval_required': True})
    else:
